-- ============================================
-- DISCOUNT CODE VALIDATION FUNCTION
-- ============================================

CREATE OR REPLACE FUNCTION validate_discount_code(
  p_code          VARCHAR,
  p_user_id       UUID,
  p_order_amount  DECIMAL,
  p_applicable_to VARCHAR DEFAULT 'all'
)
RETURNS JSON
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
  v_discount     discounts%ROWTYPE;
  v_user_uses    INTEGER;
  v_discount_amt DECIMAL(10, 2);
BEGIN
  SELECT * INTO v_discount
  FROM discounts
  WHERE UPPER(code) = UPPER(p_code)
    AND is_active = true
    AND (valid_from  IS NULL OR valid_from  <= NOW())
    AND (valid_until IS NULL OR valid_until >= NOW());

  IF NOT FOUND THEN
    RETURN json_build_object('valid', false, 'error', 'Invalid or expired discount code.');
  END IF;

  IF v_discount.max_uses IS NOT NULL AND v_discount.current_uses >= v_discount.max_uses THEN
    RETURN json_build_object('valid', false, 'error', 'This discount code has reached its usage limit.');
  END IF;

  SELECT COUNT(*) INTO v_user_uses
  FROM discount_usages
  WHERE discount_id = v_discount.id AND user_id = p_user_id AND status = 'applied';

  IF v_user_uses >= v_discount.max_uses_per_user THEN
    RETURN json_build_object('valid', false, 'error', 'You have already used this discount code.');
  END IF;

  IF p_order_amount < v_discount.min_order_amount THEN
    RETURN json_build_object(
      'valid', false,
      'error', format('A minimum order amount of ₹%s is required to use this code.', v_discount.min_order_amount)
    );
  END IF;

  IF v_discount.applicable_to != 'all' AND v_discount.applicable_to != p_applicable_to THEN
    RETURN json_build_object('valid', false, 'error', 'This discount code is not applicable for this order type.');
  END IF;

  IF v_discount.is_first_order_only THEN
    IF EXISTS (
      SELECT 1 FROM orders
      WHERE user_id = p_user_id AND status NOT IN ('cancelled', 'failed') LIMIT 1
    ) THEN
      RETURN json_build_object('valid', false, 'error', 'This discount code is only valid on your first order.');
    END IF;
  END IF;

  IF v_discount.discount_type = 'percentage' THEN
    v_discount_amt := ROUND(p_order_amount * v_discount.discount_value / 100.0, 2);
    IF v_discount.max_discount_amount IS NOT NULL THEN
      v_discount_amt := LEAST(v_discount_amt, v_discount.max_discount_amount);
    END IF;
  ELSE
    v_discount_amt := LEAST(v_discount.discount_value, p_order_amount);
  END IF;

  RETURN json_build_object(
    'valid',                true,
    'discount_id',          v_discount.id,
    'discount_type',        v_discount.discount_type,
    'discount_value',       v_discount.discount_value,
    'discount_amount',      v_discount_amt,
    'final_amount',         ROUND(p_order_amount - v_discount_amt, 2),
    'max_discount_orders',  v_discount.max_discount_orders
  );
END;
$$;

COMMENT ON FUNCTION validate_discount_code IS
  'Validates a promo code for a given user and order amount. Safe to call from the app layer before inserting a discount_usage row.';

-- ============================================
-- REFERRAL CODE: check_referral_code FUNCTION
-- ============================================
-- Lightweight read-only check used for inline UI validation.
-- Does NOT apply the code — use apply_referral_code for that.

DROP FUNCTION IF EXISTS check_referral_code(TEXT);

CREATE OR REPLACE FUNCTION check_referral_code(p_code TEXT)
RETURNS JSON
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_caller_id UUID := auth.uid();
BEGIN
  IF v_caller_id IS NULL THEN
    RETURN json_build_object('valid', false, 'error', 'Not authenticated.');
  END IF;

  IF EXISTS (
    SELECT 1 FROM users WHERE id = v_caller_id AND referred_by IS NOT NULL
  ) THEN
    RETURN json_build_object('valid', false, 'error', 'You have already used a referral code.');
  END IF;

  IF NOT EXISTS (
    SELECT 1 FROM users
    WHERE UPPER(referral_code) = UPPER(TRIM(p_code))
      AND id != v_caller_id
  ) THEN
    RETURN json_build_object('valid', false, 'error', 'Invalid referral code.');
  END IF;

  RETURN json_build_object('valid', true);
END;
$$;

COMMENT ON FUNCTION check_referral_code IS
  'Read-only check: returns { valid: true } if the code exists, is not the caller''s own code, '
  'and the caller has not already used a referral code. Does NOT apply the code.';

